defmodule MyApp.Accounts.User do
  use Ecto.Schema
  import Ecto.Changeset
  import Comeonin.Bcrypt # Assumes Comeonin.Bcrypt is installed for password hashing

  schema "users" do
    field :email, :string
    field :name, :string
    field :password, :string # Stores the hashed password
    field :unhashed_password, :string, virtual: true, redact: true # Virtual field for input

    timestamps()
  end

  @doc """
  A changeset for creating new users.
  """
  def changeset(user, attrs) do
    user
    |> cast(attrs, [:email, :name, :unhashed_password])
    |> validate_required([:email, :name, :unhashed_password])
    |> validate_length(:unhashed_password, min: 8)
    |> unique_constraint(:email, name: :users_email_index)
    |> put_hashed_password()
  end

  @doc """
  A changeset for updating existing users.
  It allows all fields defined in the schema to be cast and makes all submitted fields required.
  """
  def update_changeset(user, attrs) do
    # Get all database fields from the schema, and manually add the virtual password field
    all_updatable_fields = User.__schema__(:fields) ++ [:unhashed_password]

    user
    |> cast(attrs, all_updatable_fields) # Allows casting any field defined in the schema or virtual
    |> unsafe_validate_required(Map.keys(attrs)) # Makes all *submitted* fields required
    # Example: if attrs is %{"email": "new@example.com"}, then :email is required.
    # If attrs is %{"unhashed_password": "new_password"}, then :unhashed_password is required.
    |> validate_length(:unhashed_password, min: 8, allow_nil: true) # Only validate length if password is provided
    |> unique_constraint(:email, name: :users_email_index) # Ensures updated email remains unique
    |> put_hashed_password()
  end

  defp put_hashed_password(changeset) do
    case get_change(changeset, :unhashed_password) do
      nil ->
        changeset
      unhashed_password ->
        put_change(changeset, :password, Bcrypt.hashpwsalt(unhashed_password))
        |> delete_change(:unhashed_password) # Remove the virtual field after hashing
    end
  end

  @doc """
  Checks if a plaintext password matches the user's hashed password.
  """
  def verify_password(password, user) do
    Bcrypt.checkpw(password, user.password)
  end
end

